import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine();
        if (line == null) return;
        int T = Integer.parseInt(line.trim());
        StringBuilder out = new StringBuilder();
        for (int t = 0; t < T; t++) {
            // read integer a
            String aLine = br.readLine();
            while (aLine != null && aLine.isEmpty()) aLine = br.readLine();
            int a = Integer.parseInt(aLine.trim());
            out.append("After assigning int: a = ").append(a).append(", b = garbage, c = garbage\n");
            // read float b
            String bLine = br.readLine();
            while (bLine != null && bLine.isEmpty()) bLine = br.readLine();
            float b = Float.parseFloat(bLine.trim());
            out.append(String.format("After assigning float: a = garbage, b = %.2f, c = garbage\n", b));
            // read char c
            String cLine = br.readLine();
            while (cLine != null && cLine.isEmpty()) cLine = br.readLine();
            char c = cLine.trim().charAt(0);
            out.append("After assigning char: a = garbage, b = garbage, c = ").append(c).append('\n');
        }
        System.out.print(out.toString());
    }
}

